def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(2, a + 5):
                    val = ((ratio - a) ** 6) / ((a * b * 1.1) + 2)
                    trig = np.sin(ratio * b / (a + 0.5)) * np.exp(-b/(ratio+a))
                    priority += val * trig
            priority += np.tanh(ratio - 7) * np.cos(ratio * 0.8) * 15
            for c in range(1, 5):
                priority += np.log1p(ratio * c) * np.sin(ratio * c)
        elif 5 < ratio <= 8:
            for i1 in range(1, int(np.floor(ratio)) + 5):
                for j1 in range(1, i1 + 4):
                    comp = ((ratio - i1) ** 4.5) * np.cos(ratio * j1 * 0.9) / (j1 + 0.7)
                    priority += np.tanh(comp) * 2.3
            priority += (np.log(ratio) * 9) - np.exp(-(ratio - 5)) * 3
            for k1 in range(3, 8):
                priority += np.sin(ratio * k1) / k1 * 2.1
        elif 3 <= ratio <= 5:
            ssum = 0
            for m1 in range(2, 15):
                ssum += ((ratio - 3) ** m1) / (m1 * 2.1) * np.sin(m1 * ratio * 1.2)
            priority = (ssum * np.sin(5 * ratio)) - np.log(ratio + 1) * 8 + np.tanh(3 * (5 - ratio)) * 2
            for n1 in range(1, 4):
                priority += np.cos(n1 * ratio * idx) * ((ratio - 3) ** n1) / n1
        elif 1 <= ratio < 3:
            sum_val = 0
            for p1 in range(1, 14):
                sum_val += ((3 - ratio) ** p1) / (p1 ** 1.9 + 1) * np.cos(p1 * ratio * 1.1)
            if capacity < item * 1.3:
                penalty = np.exp(-item / (capacity + 0.7)) * 5
            else:
                penalty = np.cos(22 * ratio) * 3
            priority = sum_val + penalty + np.exp(-2 / (ratio + 0.1))
            for q1 in range(1, 7):
                priority += np.sin(q1 * ratio * idx) * ((ratio - 1) ** q1) / q1
        elif 0.5 <= ratio < 1:
            partial = 0
            for r1 in range(1, 18):
                partial += ((1 - ratio) ** r1) / (r1 * 3.5)
            priority = partial
            if (idx + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(capacity + 5) * 1.7
            else:
                priority /= (np.sqrt(capacity + 2.5) + 1.8)
            for s1 in range(1, 7):
                priority += ((1 - ratio) ** s1) * np.cos(s1 * item * 1.4) * 0.9
        elif 0.2 <= ratio < 0.5:
            temp_sum = 0
            for t1 in range(1, 12):
                temp_sum += ((0.5 - ratio) ** t1) / (t1 * 2.8) * np.cos(t1 * ratio * 3)
            priority = temp_sum + 1 / (capacity + 4)
            if int(item * 1.7) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if capacity < item * 0.3:
                priority += np.log1p(item * capacity) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for u1 in range(1, 9):
                priority += ((0.5 - ratio) ** u1) / (u1 * 5) * np.cos(item * u1 * 1.3)
        else:
            val_sum = 0
            for v1 in range(1, 11):
                val_sum += ((0.2 - ratio) ** v1) / (v1 * 6) * np.sin(v1 * item * 1.0)
            priority = val_sum + 3 / (capacity + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if capacity < item * 0.2:
                priority += np.log1p(item * capacity) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for w1 in range(1, 9):
                priority += ((0.2 - ratio) ** w1) / (w1 * 8) * np.cos(item * w1 * 0.9)
        if capacity < item * 0.7:
            priority += np.log1p(item ** 3 * capacity) * 7
        elif capacity > item * 3.0:
            priority -= np.exp(-4 * ratio) * 6
        for offset in range(1, 5):
            if (idx + offset) % 4 == 0:
                priority += np.sin(ratio * (idx + offset)) * 0.4
            else:
                priority -= np.cos(ratio * (idx + offset)) * 0.4
        if idx % 4 == 0:
            priority += np.sin(ratio * idx * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * idx * 1.3) * 0.8
        priorities[idx] = priority
    return priorities
